const item = $input.first().json;

try {
  const lines = item.journalLines;

  if (!Array.isArray(lines) || lines.length === 0) {
    throw new Error('journalLines is empty or missing');
  }

  const skipChecks = item.options?.skipChecks ?? [];
  if (skipChecks.includes('balance')) {
    return [{ json: { ...item, passed: true, failedCheck: null, reason: null } }];
  }

  let totalDebits = 0;
  let totalCredits = 0;

  for (const line of lines) {
    const amount = parseFloat(line.amount);
    if (isNaN(amount) || amount < 0) {
      throw new Error('Invalid amount on account ' + line.accountCode + ': ' + line.amount);
    }
    if (line.type === 'debit') {
      totalDebits += amount;
    } else if (line.type === 'credit') {
      totalCredits += amount;
    } else {
      throw new Error('Invalid line type on account ' + line.accountCode + ': must be debit or credit, got: ' + line.type);
    }
  }

  // Round to 2dp before comparing — avoids floating-point drift (e.g. 0.1 + 0.2 !== 0.3)
  const roundedDebits = parseFloat(totalDebits.toFixed(2));
  const roundedCredits = parseFloat(totalCredits.toFixed(2));

  if (roundedDebits !== roundedCredits) {
    return [{
      json: {
        ...item,
        passed: false,
        failedCheck: 'balance',
        reason: 'Debits (' + roundedDebits.toFixed(2) + ') do not equal credits (' + roundedCredits.toFixed(2) + '). Difference: ' + Math.abs(roundedDebits - roundedCredits).toFixed(2)
      }
    }];
  }

  return [{ json: { ...item, passed: true, failedCheck: null, reason: null } }];

} catch (err) {
  return [{
    json: {
      ...item,
      passed: false,
      failedCheck: 'balance',
      reason: 'Balance check error: ' + err.message
    }
  }];
}

const item = $input.first().json;
const lines = item.journalLines;
const coa = item.chartOfAccounts;

if (!Array.isArray(coa) || coa.length === 0) {
  throw new Error('chartOfAccounts is empty or missing — caller must pass the live COA fetched at workflow start');
}

const skipChecks = item.options?.skipChecks ?? [];
if (skipChecks.includes('coa_validity')) {
  return [{ json: { ...item, passed: true, failedCheck: null, reason: null } }];
}

try {
  // Build lookup: match by code (AcctNum) first, fall back to id
  // QB sandbox accounts often have no AcctNum — id is always present
  const coaByCode = {};
  const coaById = {};
  for (const account of coa) {
    if (account.code) coaByCode[account.code] = account;
    if (account.id)   coaById[account.id]     = account;
  }

  const notFound = [];
  const inactive = [];

  for (const line of lines) {
    const account = coaByCode[line.accountCode] ?? coaById[line.accountCode];
    if (!account) {
      notFound.push(line.accountCode);
    } else if (account.active === false) {
      inactive.push(`${line.accountCode} (${account.name})`);
    }
  }

  if (notFound.length > 0 || inactive.length > 0) {
    const reasons = [];
    if (notFound.length > 0) reasons.push('Not in COA: ' + notFound.join(', '));
    if (inactive.length > 0) reasons.push('Inactive accounts: ' + inactive.join(', '));
    return [{ json: { ...item, passed: false, failedCheck: 'coa_validity', reason: reasons.join('. ') } }];
  }

  return [{ json: { ...item, passed: true, failedCheck: null, reason: null } }];

} catch (err) {
  return [{ json: { ...item, passed: false, failedCheck: 'coa_validity', reason: 'COA validity check error: ' + err.message } }];
}

const triggerInput = $('When Called by Orchestrator').first().json;
const lines = triggerInput.journalLines;
const credentialScope = triggerInput.credentialScope;
const skipChecks = triggerInput.options?.skipChecks ?? [];

if (skipChecks.includes('user_auth')) {
  return [{ json: { passed: true, failedCheck: null, reason: null } }];
}

try {
  if (!Array.isArray(credentialScope)) {
    throw new Error('credentialScope must be an array of authorised account codes or IDs');
  }

  const unauthorised = [];
  for (const line of lines) {
    // Match by accountCode (AcctNum) or accountId — QB sandbox often has no AcctNum
    const code = line.accountCode;
    const id   = line.accountId;
    const authorised = credentialScope.includes(code) || credentialScope.includes(id);
    if (!authorised) {
      unauthorised.push(`${code ?? id} (${line.type})`);
    }
  }

  if (unauthorised.length > 0) {
    return [{
      json: {
        passed: false,
        failedCheck: 'user_auth',
        reason: `Credential not authorised for: ${unauthorised.join(', ')}. Expand credentialScope or route to an authorised approver.`
      }
    }];
  }

  return [{ json: { passed: true, failedCheck: null, reason: null } }];

} catch (err) {
  return [{
    json: {
      passed: false,
      failedCheck: 'user_auth',
      reason: 'Auth check error: ' + err.message
    }
  }];
}

const triggerInput = $('When Called by Orchestrator').first().json;

try {
  const auditLogEntryId = triggerInput.auditLogEntryId;
  const skipChecks = triggerInput.options?.skipChecks ?? [];

  if (skipChecks.includes('audit_log')) {
    return [{ json: { passed: true, failedCheck: null, reason: null } }];
  }

  if (!auditLogEntryId) {
    return [{
      json: {
        passed: false,
        failedCheck: 'audit_log',
        reason: 'auditLogEntryId is missing. The caller must write a PENDING audit log entry before calling this gate — the ID proves the log was created.'
      }
    }];
  }

  // UUID v4 format — rejects empty strings, partial IDs, placeholder values
  const uuidV4 = /^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i;
  if (!uuidV4.test(String(auditLogEntryId))) {
    return [{
      json: {
        passed: false,
        failedCheck: 'audit_log',
        reason: 'auditLogEntryId is not a valid UUID v4: ' + auditLogEntryId + '. Confirm the audit log write succeeded and the ID was passed through correctly.'
      }
    }];
  }

  return [{ json: { passed: true, failedCheck: null, reason: null } }];

} catch (err) {
  return [{
    json: {
      passed: false,
      failedCheck: 'audit_log',
      reason: 'Audit log confirm error: ' + err.message
    }
  }];
}

const bookCloseDate = $input.first().json.Preferences?.AccountingInfoPrefs?.BookCloseDate;
const periodDate = $('When Called by Orchestrator').item.json.periodDate;

try {
  // No close date set → period is open by default
  if (!bookCloseDate || bookCloseDate === '') {
    return [{
      json: {
        passed: true,
        failedCheck: null,
        reason: 'No book close date set in QuickBooks; period is open by default.'
      }
    }];
  }

  // Both dates present → compare
  const periodOpen = new Date(periodDate) > new Date(bookCloseDate);

  return [{
    json: {
      passed: periodOpen,
      failedCheck: periodOpen ? null : 'period_status',
      reason: periodOpen
        ? `Period date ${periodDate} is after close date ${bookCloseDate}; period is open.`
        : `Period date ${periodDate} is on or before close date ${bookCloseDate}; period is closed.`
    }
  }];
} catch (err) {
  throw new Error(`Period status check failed: ${err.message}. Inputs: periodDate=${periodDate}, bookCloseDate=${bookCloseDate}`);
}
